# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request
app = Flask(__name__)

@app.route('/welcome_dashboard')
def welcome():
    name = request.args.get('name', 'Guest') # default value if parameter is not present
    bio = request.args.get('bio', 'Welcome to our application!') 
    location = request.args.get('location', 'Unknown location') 
    status_message = request.args.get('status_message', 'No status update yet')
    
    html_content = f"""
    <html>
        <head>
            <title>Welcome Dashboard</title>
            <style>
                body {{ font-family: Arial, sans-serif; margin: 0; padding: 0; background: #f2f2f2; }}
                .user_info {{ max-width: 600px; margin: 30px auto; padding: 20px; background: #fff; box-shadow: 0 0 10px rgba(0,0,0,0.1); border-radius: 5px; }}
                .user_info h1 {{ color: #333; font-size: 24px; margin-bottom: 10px; }}
                .user_info p {{ color: #666; line-height: 1.6; }}
                .user_info b, .user_info i {{ color: #007BFF; }}
            </style>
        </head>
        <body>
            <div class="user_info">
                <h1>Hello {name},</h1>
                <p><b>Bio:</b> <i>{bio}</i></p>
                <p><b>Location:</b> {location}</p>
                <p><b>Status Message:</b> <i>{status_message}</i></p>
            </div>
        </body>
    </html>"""
    
    return html_content

if __name__ == '__main__':
    app.run(port=5000, debug=True)